public func encode(_ urlRequest: any URLRequestConvertible, with parameters: Parameters?) throws -> URLRequest {
    var urlRequest = try urlRequest.asURLRequest()

    guard let parameters else { return urlRequest }

    if let method = urlRequest.method, destination.encodesParametersInURL(for: method) {
        guard let url = urlRequest.url else {
            throw AFError.parameterEncodingFailed(reason: .missingURL)
        }

        if var urlComponents = URLComponents(url: url, resolvingAgainstBaseURL: false), !parameters.isEmpty {
            let percentEncodedQuery = (urlComponents.percentEncodedQuery.map { $0 + "&" } ?? "") + query(parameters)
            urlComponents.percentEncodedQuery = percentEncodedQuery
            urlRequest.url = urlComponents.url
        }
    } else {
        if urlRequest.headers["Content-Type"] == nil {
            urlRequest.headers.update(.contentType("application/x-www-form-urlencoded; charset=utf-8"))
        }

        urlRequest.httpBody = Data(query(parameters).utf8)
    }

    return urlRequest
}

fileprivate func addHandlerSync(
    _ handler: ChannelHandler,
    name: String? = nil,
    position: ChannelPipeline.SynchronousOperations.Position = .last
) -> Result<Void, Error> {
    self.eventLoop.assertInEventLoop()

    if self.destroyed {
        return .failure(ChannelError._ioOnClosedChannel)
    }

    switch position {
    case .first:
        return self.add0(
            name: name,
            handler: handler,
            relativeContext: head!,
            operation: self.add0(context:after:)
        )
    case .last:
        return self.add0(
            name: name,
            handler: handler,
            relativeContext: tail!,
            operation: self.add0(context:before:)
        )
    case .before(let beforeHandler):
        return self.add0(
            name: name,
            handler: handler,
            relativeHandler: beforeHandler,
            operation: self.add0(context:before:)
        )
    case .after(let afterHandler):
        return self.add0(
            name: name,
            handler: handler,
            relativeHandler: afterHandler,
            operation: self.add0(context:after:)
        )
    }
}

public struct _DependencyKeyWritingReducer<Base: Reducer>: Reducer {
  @usableFromInline
  let base: Base

  @usableFromInline
  let update: (inout DependencyValues) -> Void

  @usableFromInline
  init(base: Base, update: @escaping (inout DependencyValues) -> Void) {
    self.base = base
    self.update = update
  }

  @inlinable
  public func _reduce(
    into state: inout Base.State, action: Base.Action
  ) -> Effect<Base.Action> {
    withDependencies {
      self.update(&$0)
    } operation: {
      self.base._reduce(into: &state, action: action)
    }
  }

  @inlinable
  public func dependency<Value>(
    _ keyPath: WritableKeyPath<DependencyValues, Value>,
    _ value: Value
  ) -> Self {
    Self(base: self.base) { values in
      values[keyPath: keyPath] = value
      self.update(&values)
    }
  }

  @inlinable
  public func transformDependency<V>(
    _ keyPath: WritableKeyPath<DependencyValues, V>,
    transform: @escaping (inout V) -> Void
  ) -> Self {
    Self(base: self.base) { values in
      transform(&values[keyPath: keyPath])
      self.update(&values)
    }
  }
}

