enum File {
  @TaskLocal static var counter = Counter()

  final class Counter: @unchecked Sendable {
    private var counts: [String: Int] = [:]
    private let lock = NSLock()

    init() {}

    func next(for key: String) -> Int {
      lock.lock()
      defer { lock.unlock() }
      counts[key, default: 0] += 1
      return counts[key]!
    }

    func reset() {
      lock.lock()
      defer { lock.unlock() }
      counts.removeAll()
    }
  }
}

